svg.script:
(function () {
  "use strict";

  var SVGNS  = "http://www.w3.org/2000/svg";
  var XHTML  = "http://www.w3.org/1999/xhtml";
  var doc    = document;
  var statusEl = doc.getElementById("status");
  function setStatus(s) { statusEl.textContent = s; }

  // ---------- Web Audio (lazy) ----------
  var actx = null;
  function audio() {
    if (!actx) {
      var AC = window.AudioContext || window.webkitAudioContext;
      actx = new AC();
    }
    if (actx.state === "suspended") { actx.resume(); }
    return actx;
  }

  // ---------- State ----------
  var octave   = 4;                 // lowest C of the keyboard = 12*(octave+1)
  var waveform = "sine";
  var waves    = ["sine", "square", "triangle", "sawtooth"];
  var voices   = {};                // id -> {osc, gain}

  // recording
  var recording = false;
  var recStart  = 0;
  var recEvents = [];               // {t(ms), on(bool), midi, vel}
  var playTimers = [];

  function baseMidi() { return 12 * (octave + 1); }
  function midiToFreq(m) { return 440 * Math.pow(2, (m - 69) / 12); }

  // ---------- Synth voice ----------
  function startVoice(id, midi, el) {
    if (voices[id]) { return; }
    var a = audio();
    var osc = a.createOscillator();
    var g   = a.createGain();
    osc.type = waveform;
    osc.frequency.value = midiToFreq(midi);
    g.gain.setValueAtTime(0.0001, a.currentTime);
    g.gain.exponentialRampToValueAtTime(0.25, a.currentTime + 0.012);
    osc.connect(g).connect(a.destination);
    osc.start();
    voices[id] = { osc: osc, gain: g };
    if (el) { el.classList.add("active"); }
  }
  function stopVoice(id, el) {
    var v = voices[id];
    if (!v) { return; }
    var a = audio();
    var now = a.currentTime;
    v.gain.gain.cancelScheduledValues(now);
    v.gain.gain.setValueAtTime(Math.max(v.gain.gain.value, 0.0001), now);
    v.gain.gain.exponentialRampToValueAtTime(0.0001, now + 0.12);
    v.osc.stop(now + 0.14);
    delete voices[id];
    if (el) { el.classList.remove("active"); }
  }

  // ---------- Manual play (records if armed) ----------
  function manualOn(id, semi, el) {
    var midi = baseMidi() + semi;
    startVoice(id, midi, el);
    if (recording) { recEvents.push({ t: performance.now() - recStart, on: true,  midi: midi, vel: 100 }); }
  }
  function manualOff(id, semi, el) {
    var midi = baseMidi() + semi;
    if (voices[id] && recording) { recEvents.push({ t: performance.now() - recStart, on: false, midi: midi, vel: 0 }); }
    stopVoice(id, el);
  }

  // ---------- Keyboard geometry ----------
  var OCTAVES   = 4;
  var WKEY_W = 32, WKEY_H = 200, BKEY_W = 20, BKEY_H = 124;
  var W_SEMI = [0, 2, 4, 5, 7, 9, 11];          // white semitones in an octave
  var B_SEMI = [1, 3, 6, 8, 10];                // black semitones
  var B_AFTER = [0, 1, 3, 4, 5];                // black sits after which white index (within octave)
  var KBD = { a:0, s:2, d:4, f:5, g:7, h:9, j:11, k:12, l:14,
              w:1, e:3, t:6, y:8, u:10, o:13, p:15 };

  var keysG    = doc.getElementById("keys");
  var byKey    = {};   // keyboard char -> {id, semi, el}
  var semiToEl = {};   // semi offset -> key element (for playback highlight)
  var keyDefs  = [];

  function txt(cls, x, y, s) {
    var t = doc.createElementNS(SVGNS, "text");
    t.setAttribute("class", cls); t.setAttribute("x", x); t.setAttribute("y", y);
    t.textContent = s; return t;
  }
  function bind(rect, id, semi) {
    rect.addEventListener("mousedown",  function (e) { e.preventDefault(); manualOn(id, semi, rect); });
    rect.addEventListener("mouseup",    function () { manualOff(id, semi, rect); });
    rect.addEventListener("mouseleave", function () { manualOff(id, semi, rect); });
    rect.addEventListener("touchstart", function (e) { e.preventDefault(); manualOn(id, semi, rect); }, { passive: false });
    rect.addEventListener("touchend",   function (e) { e.preventDefault(); manualOff(id, semi, rect); }, { passive: false });
  }

  var totalWhites = OCTAVES * 7 + 1;            // include final C
  var wi = 0;
  for (var o = 0; o < OCTAVES; o++) {
    for (var n = 0; n < 7; n++) {
      (function (index, semi) {
        var x = index * WKEY_W;
        var r = doc.createElementNS(SVGNS, "rect");
        r.setAttribute("class", "white");
        r.setAttribute("x", x); r.setAttribute("y", 0);
        r.setAttribute("width", WKEY_W); r.setAttribute("height", WKEY_H);
        r.setAttribute("rx", 4);
        keysG.appendChild(r);
        var name = ["C","D","E","F","G","A","B"][semi === 0 ? 0 : [0,2,4,5,7,9,11].indexOf(semi % 12)];
        keysG.appendChild(txt("wlabel", x + WKEY_W / 2, WKEY_H - 10, name + (octave + Math.floor((semi)/12))));
        var id = "w" + index;
        bind(r, id, semi);
        semiToEl[semi] = r;
        keyDefs.push({ el: r, semi: semi });
      })(wi, o * 12 + W_SEMI[n]);
      wi++;
    }
  }
  // final high C
  (function (index, semi) {
    var x = index * WKEY_W;
    var r = doc.createElementNS(SVGNS, "rect");
    r.setAttribute("class", "white");
    r.setAttribute("x", x); r.setAttribute("y", 0);
    r.setAttribute("width", WKEY_W); r.setAttribute("height", WKEY_H);
    r.setAttribute("rx", 4);
    keysG.appendChild(r);
    keysG.appendChild(txt("wlabel", x + WKEY_W / 2, WKEY_H - 10, "C" + (octave + OCTAVES)));
    bind(r, "w" + index, semi);
    semiToEl[semi] = r;
    keyDefs.push({ el: r, semi: semi });
  })(wi, OCTAVES * 12);

  // black keys (rendered on top)
  for (var ob = 0; ob < OCTAVES; ob++) {
    for (var bn = 0; bn < 5; bn++) {
      (function (octIdx, semi, afterWhite) {
        var whiteIndex = octIdx * 7 + afterWhite;
        var x = (whiteIndex + 1) * WKEY_W - BKEY_W / 2;
        var r = doc.createElementNS(SVGNS, "rect");
        r.setAttribute("class", "black");
        r.setAttribute("x", x); r.setAttribute("y", 0);
        r.setAttribute("width", BKEY_W); r.setAttribute("height", BKEY_H);
        r.setAttribute("rx", 3);
        keysG.appendChild(r);
        var id = "b" + octIdx + "_" + bn;
        bind(r, id, semi);
        semiToEl[semi] = r;
        keyDefs.push({ el: r, semi: semi });
      })(ob, ob * 12 + B_SEMI[bn], B_AFTER[bn]);
    }
  }

  // computer keyboard bindings
  Object.keys(KBD).forEach(function (ch) {
    var semi = KBD[ch];
    byKey[ch] = { id: "kbd_" + ch, semi: semi, el: semiToEl[semi] || null };
  });
  doc.addEventListener("keydown", function (e) {
    if (e.repeat) { return; }
    var k = byKey[(e.key || "").toLowerCase()];
    if (k) { manualOn(k.id, k.semi, k.el); }
  });
  doc.addEventListener("keyup", function (e) {
    var k = byKey[(e.key || "").toLowerCase()];
    if (k) { manualOff(k.id, k.semi, k.el); }
  });

  // ============================================================
  //  MIDI  (Standard MIDI File, format 0)
  // ============================================================
  var TPQ = 480, BPM = 120;
  var US_PER_QN = Math.round(60000000 / BPM);
  var TICKS_PER_MS = TPQ * BPM / 60000;          // 0.96 at 480tpq/120bpm

  function varLen(value) {
    var bytes = [value & 0x7f];
    value >>= 7;
    while (value > 0) { bytes.unshift((value & 0x7f) | 0x80); value >>= 7; }
    return bytes;
  }
  function pushStr(arr, s) { for (var i = 0; i < s.length; i++) { arr.push(s.charCodeAt(i)); } }
  function push32(arr, v) { arr.push((v>>>24)&0xff,(v>>>16)&0xff,(v>>>8)&0xff,v&0xff); }
  function push16(arr, v) { arr.push((v>>>8)&0xff, v&0xff); }

  function buildMidi(events) {
    var evs = events.slice().sort(function (a, b) { return a.t - b.t; });
    var track = [];
    // tempo meta
    track.push(0x00, 0xff, 0x51, 0x03, (US_PER_QN>>16)&0xff, (US_PER_QN>>8)&0xff, US_PER_QN&0xff);
    var prevTick = 0;
    evs.forEach(function (e) {
      var tick = Math.round(e.t * TICKS_PER_MS);
      var delta = Math.max(0, tick - prevTick);
      prevTick = tick;
      varLen(delta).forEach(function (b) { track.push(b); });
      track.push(e.on ? 0x90 : 0x80, e.midi & 0x7f, e.vel & 0x7f);
    });
    track.push(0x00, 0xff, 0x2f, 0x00); // end of track

    var out = [];
    pushStr(out, "MThd"); push32(out, 6); push16(out, 0); push16(out, 1); push16(out, TPQ);
    pushStr(out, "MTrk"); push32(out, track.length);
    for (var i = 0; i < track.length; i++) { out.push(track[i]); }
    return new Uint8Array(out);
  }

  function parseMidi(buffer) {
    var dv = new DataView(buffer);
    var p = 0;
    function str(n) { var s = ""; for (var i = 0; i < n; i++) { s += String.fromCharCode(dv.getUint8(p++)); } return s; }
    function u32() { var v = dv.getUint32(p); p += 4; return v; }
    function u16() { var v = dv.getUint16(p); p += 2; return v; }
    function u8()  { return dv.getUint8(p++); }
    function vlen() { var v = 0, b; do { b = u8(); v = (v << 7) | (b & 0x7f); } while (b & 0x80); return v; }

    if (str(4) !== "MThd") { throw new Error("not a MIDI file"); }
    u32(); u16();                       // header length, format
    var ntrks = u16();
    var division = u16();

    var all = [];                       // {tick, type:'on'/'off'/'tempo', midi, us}
    for (var tr = 0; tr < ntrks; tr++) {
      if (str(4) !== "MTrk") { break; }
      var len = u32();
      var end = p + len;
      var tick = 0, running = 0;
      while (p < end) {
        tick += vlen();
        var status = dv.getUint8(p);
        if (status & 0x80) { running = status; p++; } else { status = running; }
        var hi = status & 0xf0;
        if (status === 0xff) {           // meta
          var meta = u8(); var mlen = vlen();
          if (meta === 0x51 && mlen === 3) {
            var us = (u8() << 16) | (u8() << 8) | u8();
            all.push({ tick: tick, type: "tempo", us: us });
          } else { p += mlen; }
        } else if (status === 0xf0 || status === 0xf7) { // sysex
          var slen = vlen(); p += slen;
        } else if (hi === 0x90) {
          var n1 = u8(), v1 = u8();
          all.push({ tick: tick, type: v1 > 0 ? "on" : "off", midi: n1 });
        } else if (hi === 0x80) {
          var n2 = u8(); u8();
          all.push({ tick: tick, type: "off", midi: n2 });
        } else if (hi === 0xa0 || hi === 0xb0 || hi === 0xe0) {
          p += 2;
        } else if (hi === 0xc0 || hi === 0xd0) {
          p += 1;
        } else { p++; }
      }
      p = end;
    }

    all.sort(function (a, b) { return a.tick - b.tick; });
    var curUs = 500000, lastTick = 0, curMs = 0, notes = [];
    all.forEach(function (e) {
      curMs += (e.tick - lastTick) * (curUs / 1000 / division);
      lastTick = e.tick;
      if (e.type === "tempo") { curUs = e.us; }
      else { notes.push({ t: curMs, on: e.type === "on", midi: e.midi }); }
    });
    return notes;
  }

  // ---------- Playback of a note list ----------
  function clearTimers() { playTimers.forEach(clearTimeout); playTimers = []; }
  function stopAll() {
    clearTimers();
    Object.keys(voices).forEach(function (id) { stopVoice(id, null); });
    keyDefs.forEach(function (k) { k.el.classList.remove("active"); });
  }
  function elForMidi(midi) {
    var semi = midi - baseMidi();
    return semiToEl[semi] || null;
  }
  function playNotes(notes, label) {
    if (!notes.length) { setStatus("nothing to play"); return; }
    audio();
    stopAll();
    setStatus((label || "playing") + "\u2026");
    var maxT = 0;
    notes.forEach(function (e) {
      maxT = Math.max(maxT, e.t);
      var id = "pb_" + e.midi;
      playTimers.push(setTimeout(function () {
        if (e.on) { startVoice(id, e.midi, elForMidi(e.midi)); }
        else      { stopVoice(id, elForMidi(e.midi)); }
      }, e.t));
    });
    playTimers.push(setTimeout(function () { setStatus("done"); }, maxT + 200));
  }

  // ---------- File helpers (XHTML elements work in top-level SVG) ----------
  function download(bytes, name) {
    var blob = new Blob([bytes], { type: "audio/midi" });
    var url  = URL.createObjectURL(blob);
    var a = doc.createElementNS(XHTML, "a");
    a.setAttribute("href", url);
    a.setAttribute("download", name);
    doc.documentElement.appendChild(a);
    a.click();
    setTimeout(function () { a.remove(); URL.revokeObjectURL(url); }, 200);
  }
  function pickFile(cb) {
    var input = doc.createElementNS(XHTML, "input");
    input.setAttribute("type", "file");
    input.setAttribute("accept", ".mid,.midi,audio/midi");
    input.addEventListener("change", function () {
      if (input.files && input.files[0]) { cb(input.files[0]); }
    });
    input.click();
  }

  // ============================================================
  //  Controls
  // ============================================================
  var octLabel = doc.getElementById("octLabel");
  var waveText = doc.querySelector("#waveToggle text");
  var recBtn   = doc.getElementById("recBtn");

  function clampOct(v) { return Math.max(1, Math.min(5, v)); }
  doc.getElementById("octUp").addEventListener("click", function () {
    octave = clampOct(octave + 1); octLabel.textContent = "oct " + octave;
  });
  doc.getElementById("octDown").addEventListener("click", function () {
    octave = clampOct(octave - 1); octLabel.textContent = "oct " + octave;
  });
  doc.getElementById("waveToggle").addEventListener("click", function () {
    waveform = waves[(waves.indexOf(waveform) + 1) % waves.length];
    waveText.textContent = "wave: " + waveform;
  });

  recBtn.addEventListener("click", function () {
    recording = !recording;
    if (recording) {
      recEvents = []; recStart = performance.now();
      recBtn.classList.add("on"); setStatus("recording\u2026");
    } else {
      recBtn.classList.remove("on");
      setStatus("recorded " + recEvents.length + " events");
    }
  });
  doc.getElementById("playBtn").addEventListener("click", function () {
    if (recording) { recBtn.classList.remove("on"); recording = false; }
    playNotes(recEvents, "playing recording");
  });
  doc.getElementById("stopBtn").addEventListener("click", function () {
    stopAll(); setStatus("stopped");
  });
  doc.getElementById("exportBtn").addEventListener("click", function () {
    if (!recEvents.length) { setStatus("record something first"); return; }
    try {
      download(buildMidi(recEvents), "svg-piano.mid");
      setStatus("exported svg-piano.mid");
    } catch (err) { setStatus("export failed: " + err.message); }
  });
  doc.getElementById("importBtn").addEventListener("click", function () {
    pickFile(function (file) {
      var reader = new FileReader();
      reader.onload = function () {
        try {
          var notes = parseMidi(reader.result);
          setStatus("loaded " + file.name + " (" + notes.length + " events)");
          playNotes(notes, "playing " + file.name);
        } catch (err) { setStatus("import failed: " + err.message); }
      };
      reader.readAsArrayBuffer(file);
    });
  });

  setStatus("ready \u2014 click a key");
})();
